const apiKey = $env.GOOGLE_PLACES_API_KEY;
if (!apiKey) throw new Error('GOOGLE_PLACES_API_KEY eksik');

const sbBase = ($env.SUPABASE_URL || 'http://host.docker.internal:54321').replace(/\/$/, '');
const sbKey = $env.SUPABASE_SERVICE_ROLE_KEY || 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZS1kZW1vIiwicm9sZSI6InNlcnZpY2Vfcm9sZSIsImV4cCI6MTk4MzgxMjk5Nn0.EGIM96RAZx35lJzdJsyH-qQwv8Hdp7fsn3W0YpN81IU';

const sbHeaders = {
  apikey: sbKey,
  Authorization: `Bearer ${sbKey}`,
  'Content-Type': 'application/json',
};

async function sb(method, path, body, prefer = 'return=minimal') {
  return await this.helpers.httpRequest({
    method,
    url: `${sbBase}/rest/v1/${path}`,
    headers: { ...sbHeaders, Prefer: prefer },
    body,
    json: true,
  });
}

async function places(method, path, body, fieldMask) {
  const headers = {
    'Content-Type': 'application/json',
    'X-Goog-Api-Key': apiKey,
  };
  if (fieldMask) headers['X-Goog-FieldMask'] = fieldMask;
  return await this.helpers.httpRequest({
    method,
    url: `https://places.googleapis.com/v1${path}`,
    headers,
    body,
    json: true,
  });
}

function sentiment(r) {
  if (r >= 4) return 'positive';
  if (r === 3) return 'neutral';
  return 'negative';
}

async function resolvePlaceId(clinic) {
  if (clinic.google_place_id) return clinic.google_place_id.replace('places/', '');
  const urls = [clinic.google_maps_url, clinic.google_review_url].filter(Boolean).join(' ');
  const m = urls.match(/ChIJ[\w-]{20,}/);
  if (m) return m[0];
  const q = [clinic.name, clinic.address].filter(Boolean).join(' ');
  if (!q) return null;
  const data = await places.call(this, 'POST', '/places:searchText', {
    textQuery: q,
    languageCode: 'tr',
    regionCode: 'TR',
  }, 'places.id,places.rating,places.userRatingCount');
  const id = data.places?.[0]?.id;
  return id ? id.replace('places/', '') : null;
}

const clinics = await sb.call(this, 'GET', 'clinics?select=id,name,address,google_place_id,google_maps_url,google_review_url,google_rating,google_review_count&order=name.asc');
const results = [];

    const webhookBase = ($env.WEBHOOK_URL || $env.N8N_WEBHOOK_URL || 'http://127.0.0.1:5678/').replace(/\/$/, '');
    const sentinelHits = [];

for (const clinic of clinics) {
  try {
    const placeId = await resolvePlaceId.call(this, clinic);
    if (!placeId) {
      results.push({ clinic: clinic.name, ok: false, error: 'place_id yok' });
      continue;
    }
    const details = await places.call(this, 'GET', `/places/${encodeURIComponent(placeId)}`, undefined, 'id,rating,userRatingCount,reviews,googleMapsUri');
    await sb.call(this, 'PATCH', `clinics?id=eq.${clinic.id}`, {
      google_place_id: placeId,
      google_rating: details.rating,
      google_review_count: details.userRatingCount,
      google_reviews_synced_at: new Date().toISOString(),
      ...(details.googleMapsUri && !clinic.google_maps_url ? { google_maps_url: details.googleMapsUri } : {}),
    });
    let inserted = 0;
    for (const [i, review] of (details.reviews || []).entries()) {
      const ext = review.name?.split('/reviews/').pop() || `${clinic.id}:${i}:${review.rating}`;
      const author = review.authorAttribution?.displayName || 'Google kullanıcısı';
      const text = review.text?.text || '';
      const existing = await sb.call(this, 'GET', `google_reviews?clinic_id=eq.${clinic.id}&external_review_id=eq.${encodeURIComponent(ext)}&select=id`);
      if (existing?.length) {
        await sb.call(this, 'PATCH', `google_reviews?id=eq.${existing[0].id}`, {
          author_name: author,
          rating: review.rating,
          review_text: text,
          sentiment: sentiment(review.rating),
        });
      } else {
        await sb.call(this, 'POST', 'google_reviews', {
          clinic_id: clinic.id,
          external_review_id: ext,
          author_name: author,
          rating: review.rating,
          review_text: text,
          sentiment: sentiment(review.rating),
          status: 'pending_approval',
        });
        inserted++;
      }
    }
    results.push({ clinic: clinic.name, ok: true, placeId, rating: details.rating, total: details.userRatingCount, synced: (details.reviews || []).length, inserted });
  } catch (e) {
    results.push({ clinic: clinic.name, ok: false, error: e.message });
  }
}

return [{ json: { ok: true, at: new Date().toISOString(), results, sentinelHits } }];
